.wave_container { position: absolute; width: calc(100% - 2px); left: 2px; top: 1px; overflow: hidden; }
.wave_container svg { transition: 0.2s ease-in-out; }
.wave_container svg path { fill: rgb(81, 172, 251); opacity: 0.7; }
