drop:
@-webkit-keyframes drop { 
  0% { opacity: 1; }
  70% { transform: translateY(0px); opacity: 1; }
  100% { transform: translateY(110vh); opacity: 0.5; }
}
@keyframes drop { 
  0% { opacity: 1; }
  70% { transform: translateY(0px); opacity: 1; }
  100% { transform: translateY(110vh); opacity: 0.5; }
}
